Еве еден можен начин на кој можете да напишете JavaScript код за да го откриете типот на прелистувач што се користи за пристап до страницата:

``` Javascript
функција detectBrowser(){
    var userAgent = navigator.userAgent;
    var Име на прелистувач = "";

    if (userAgent.indexOf("Firefox") > -1){
        browserName = "Firefox";
    } else if (userAgent.indexOf("SamsungBrowser") > -1){
        // Прелистувач Samsung
        прелистувач Име = „Самсунг Интернет“;
    } else if (userAgent.indexOf("Opera") > -1 || userAgent.indexOf("OPR") > -1){
        // Opera 8.0+
        browserName = "Опера";
    } else if (userAgent.indexOf("Edg") > -1){
        // Раб (Chromium)
        browserName = "Microsoft Edge";
