        browserName = „Хром“;
    } else if (userAgent.indexOf("Safari") > -1){
        browserName = "Safari";
    } else if (userAgent.indexOf("Trident") > -1){
        // (Internet Explorer)
        browserName = "Internet Explorer";
    }друго {
      browserName = „Непознат прелистувач“;
    }

    врати Име на прелистувачот;
}

console.log('Користете ' + detectBrowser() + ' прелистувач.');
```

Овој код користи `navigator.userAgent` за да го одреди прелистувачот на корисникот врз основа на низата User-Agent. Проверува различни модели на вообичаени прелистувачи како Firefox, Chrome, Safari, Opera, Edge и потоа ги враќа нивните соодветни имиња. Ако ниту еден не се совпаѓа, враќа „Непознат прелистувач“.

